status_info = []
for doc in civic_docs:
    txt = doc.get('text', '')
    lines = txt.split('\n')
    for i in range(len(lines)):
        line = lines[i].strip()
        if len(line) > 10:
            line_lower = line.lower()
            if 'project' in line_lower or 'repairs' in line_lower or 'sirens' in line_lower:
